// Only real inbound text, and only from the owner number.
const d = $input.first().json.data || {};
if (!d.body || d.type && d.type !== 'text') return [];

const owner = ($env.SOFI_OWNER_CHAT || '').trim();
if (owner && d.from !== owner) return [];

return [{ json: {
  chatId: d.chatId || d.from,
  text: (d.body || '').trim(),
  messageId: d.id || ''
} }];

// No keyword map — the message goes to sofi-ceo as-is. CEO reads the SOFI
// routing doctrine itself (CLAUDE.md / engine/routing/routing.yaml), decides
// which of the 30 agents (or itself) should handle it, delegates via the
// Agent/Task tool if needed, does the work, checkpoints, and replies. This is
// literally the CEO's job per its own operating contract — n8n just hands it
// the raw ticket instead of pre-guessing the route with string matching.
const text = $json.text;
const project = 'PRJ-SAKK';

const command = `WhatsApp ticket from the project owner:\n\n"${text}"\n\n`
  + `Read it, decide what's actually being asked, and handle it end-to-end:\n`
  + `- Quick question/status check -> answer directly, cheaply (haiku-tier).\n`
  + `- Work that maps to a specialist (audit, fix, feature, report, security, `
  + `deploy, etc.) -> delegate via the Agent tool to the right tier agent per `
  + `your own routing doctrine (routing.yaml economic ladder) and this project's `
  + `gate. Do not skip agents to save a step; do not over-escalate model tier.\n`
  + `- If it's ambiguous or missing detail you cannot safely assume, say so `
  + `plainly instead of guessing.\n`
  + `- Checkpoint any change per SOFI git discipline before you finish.\n\n`
  + `Reply format: end with a short, WhatsApp-readable summary in Arabic `
  + `(<= 1200 chars) of what you found/did and what's next — this exact text `
  + `is sent back to the owner's phone, so no markdown tables, no file trees, `
  + `just plain readable lines.`;

const base = $env.SOFI_CALLBACK_BASE || 'http://127.0.0.1:5678';
return [{ json: {
  role: 'sofi-ceo',
  project,
  command,
  model: 'sonnet',
  mode: 'async',
  source: 'whatsapp',
  callback_url: `${base}/webhook/sofi-callback`,
  meta: { chatId: $json.chatId }
} }];
